// Find sources with recent failures or noisy warning.
// No business logic — just filtering on API-provided health data.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on bad API responses.
try {
  const input = $input.first();
  if (!input || !input.json) {
    console.warn('[source-health] No response from /sources endpoint — skipping.');
    return [];
  }
  const sources = input.json.sources;
  if (!Array.isArray(sources)) {
    console.warn('[source-health] sources is not an array — skipping. Got:', typeof sources);
    return [];
  }
  const failing = sources.filter(s => s.total_failures > 0 || s.noisy_warning || s.last_status === 'failure');
  if (!failing.length) {
    console.log('[source-health] All sources healthy — no alerts needed.');
    return [];
  }
  return failing.map(s => ({ json: s }));
} catch (err) {
  console.error('[source-health] Filter error:', err.message || String(err));
  return [];
}
